#include <iostream>
#include <vector>
// Assuming Animal, Dog, Cat classes are defined in the solution code

int main() {
    std::cout << "--- Starting animal demonstration ---\n";
    std::vector<Animal*> animals;

    Animal* animal1 = new Dog();
    animals.push_back(animal1);
    std::cout << "A new dog has joined the animal collection.\n";

    Animal* animal2 = new Cat();
    animals.push_back(animal2);
    std::cout << "A new cat has been added to the collection.\n";

    std::cout << "\n--- All animals making their sounds ---\n";
    for (Animal* currentAnimal : animals) {
        std::cout << "Current animal says: ";
        currentAnimal->makeSound();
    }

    std::cout << "\n--- Initiating manual memory cleanup ---\n";
    for (Animal* animalPtr : animals) {
        delete animalPtr; // Manual deletion, less efficient/safe than smart pointers
    }
    animals.clear(); // Clearing the vector after deleting pointers is redundant but included for verbosity
    std::cout << "--- Finished manual memory cleanup ---\n";

    return 0;
}
